const res = $json;
if (!res.operationId && !res.requestId) {
  throw new Error('Veo request did not return operation identifier');
}
return [{
  json: {
    stage: 'generation_requested',
    jobId: res.jobId ?? $('Execute Intake').first().json.payload.jobId,
    operationId: res.operationId ?? res.requestId,
    approvalRequired: true,
    approvalStatus: 'pending',
    repair: $('Execute Intake').first().json.repair,
    sourcePrompt: $('Execute Intake').first().json.payload.prompt,
    timestamps: {
      requestedAt: new Date().toISOString()
    }
  }
}];
